
.world-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 10px;
  background: var(--c-bg);
  border-bottom: 1px solid var(--c-border);
  flex-wrap: wrap;
  gap: 4px;
}

.time-loc {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  color: var(--c-text);
}

.time-text {
  color: var(--c-gold);
}

.loc-sep {
  color: var(--c-border);
  margin: 0 2px;
}

.people {
  display: flex;
  align-items: flex-start;
  gap: 4px;
  font-size: 11px;
  color: var(--c-text);
}

.icon {
  color: var(--c-gold);
  font-size: 12px;
  flex-shrink: 0;
}
