
.outfit-section {
  padding: 10px 12px;
  border-top: 1px solid var(--c-border);
  background: rgba(255, 255, 255, 0.01);
}

.section-title {
  font-size: 11px;
  font-weight: bold;
  color: var(--c-text-bright);
  border-bottom: 1px solid var(--c-border);
  padding-bottom: 4px;
  margin-bottom: 8px;
}

.outfit-layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-template-rows: auto auto;
  gap: 6px;
}

.outfit-card {
  padding: 6px 8px;
  background: var(--c-bg);
  border: 1px solid var(--c-border);
}

.outfit-card.overall {
  grid-column: 1 / 2;
  grid-row: 1 / 2;
}

.outfit-card.underwear {
  grid-column: 2 / 3;
  grid-row: 1 / 2;
  border-color: rgba(176, 124, 216, 0.25);
  background: rgba(176, 124, 216, 0.03);
}

.outfit-card.accessories {
  grid-column: 1 / 3;
  grid-row: 2 / 3;
}

.outfit-card.other {
  grid-column: 1 / 3;
  grid-row: 3 / 4;
  border-color: var(--c-gold-dim);
  background: rgba(212, 168, 83, 0.04);
}

.card-label {
  font-size: 9px;
  color: var(--c-gold);
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: 3px;
}

.underwear .card-label { color: var(--c-purple); }
.accessories .card-label { color: var(--c-text-dim); }

.card-desc {
  font-size: 10.5px;
  color: var(--c-text);
  line-height: 1.45;
  word-break: break-all;
}

.acc-list {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.acc-row {
  display: flex;
  gap: 6px;
  align-items: flex-start;
}

.acc-part {
  font-size: 9.5px;
  color: var(--c-text-dim);
  flex-shrink: 0;
  min-width: 52px;
  padding-top: 1px;
}

.acc-desc {
  font-size: 10.5px;
  color: var(--c-text);
  line-height: 1.4;
}

@media (max-width: 480px) {
  .outfit-layout {
    grid-template-columns: 1fr;
  }

  .outfit-card.overall,
  .outfit-card.underwear,
  .outfit-card.accessories,
  .outfit-card.other {
    grid-column: 1 / 2;
  }

  .outfit-card.underwear { grid-row: 2 / 3; }
  .outfit-card.accessories { grid-row: 3 / 4; }
  .outfit-card.other { grid-row: 4 / 5; }
}
