
.mind-panel {
  padding: 10px 10px 12px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.section-title {
  font-size: 11px;
  font-weight: bold;
  color: var(--c-text-bright);
  border-bottom: 1px solid var(--c-border);
  padding-bottom: 4px;
}

.sub-label {
  font-size: 10px;
  color: var(--c-text-dim);
  display: block;
  margin-bottom: 2px;
}

.clarity-row,
.resist-row {
  display: flex;
  align-items: center;
  gap: 6px;
}

.track {
  flex: 1;
  height: 8px;
  border: 1px solid var(--c-border);
  background: var(--c-bg);
  overflow: hidden;
}

.fill {
  height: 100%;
  transition: width 0.4s ease;
}

.clarity {
  background: linear-gradient(90deg, var(--c-purple-dim), var(--c-purple));
}

.resist {
  background: linear-gradient(90deg, var(--c-purple), #c39bdb);
}

.value {
  font-weight: bold;
  font-size: 11px;
  min-width: 32px;
  text-align: right;
}

.good { color: var(--c-purple); }
.warn { color: var(--c-gold); }
.danger { color: var(--c-danger); }

.feeling-block {
  flex: 1;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid var(--c-border);
  padding: 6px 8px;
}

.feeling-text {
  font-size: 10.5px;
  color: var(--c-text-dim);
  line-height: 1.5;
  margin-top: 2px;
  font-style: italic;
}
